+                    "file": f,
+                    "line": line,
+                    "primary_type": issue_type,
+                    "types": {issue_type},
+                    "severities": {str(item.get("severity", "minor"))},
+                    "desc_tokens": tokens,
+                    "findings": [item],
+                }
+            )
