@@ -0,0 +1,87 @@
+#!/usr/bin/env python3
+"""Render weighted vote verdict to markdown report."""
+
+from __future__ import annotations
+
+import argparse
+import json
+import sys
+
+
+SEVERITY_ORDER = {"critical": 0, "major": 1, "minor": 2}
+
+
+def load_json(path: str):
+    with open(path, "r", encoding="utf-8") as f:
+        return json.load(f)
+
+
+def pick_severity(findings: list[dict]) -> str:
+    values = [str(f.get("severity", "minor")).lower() for f in findings]
+    if not values:
+        return "minor"
+    return sorted(values, key=lambda s: SEVERITY_ORDER.get(s, 99))[0]
+
+
+def main() -> int:
+    parser = argparse.ArgumentParser(
+        description="Render markdown report from verdict JSON"
+    )
+    parser.add_argument("input", help="Verdict JSON from weighted_vote.py")
+    parser.add_argument(
+        "-o", "--output", help="Markdown output path (defaults to stdout)"
+    )
+    args = parser.parse_args()
+
+    data = load_json(args.input)
+    accepted = data.get("accepted", [])
+
+    accepted.sort(
+        key=lambda item: (
+            SEVERITY_ORDER.get(pick_severity(item.get("findings", [])), 99),
+            -float(item.get("score", 0.0)),
+        )
+    )
+
+    lines = []
+    lines.append("## Bug Hunter Report")
+    lines.append("")
+    lines.append(f"- Threshold: `{data.get('threshold', 0.6)}`")
+    lines.append(f"- Accepted findings: `{len(accepted)}`")
+    lines.append("")
+    lines.append("| 缺陷编号 | 位置 | 类型 | 严重级别 | 描述 | 建议修复 | 共识强度 |")
+    lines.append("|---|---|---|---|---|---|---|")
+
+    for item in accepted:
+        findings = item.get("findings", [])
+        first = findings[0] if findings else {}
+        severity = pick_severity(findings)
+        desc = str(first.get("description", "")).replace("\n", " ").strip()
+        fix = (
+            str(first.get("fix_code", "")).replace("\n", " ").strip()
+            or "(需要补充修复建议)"
+        )
+        position = f"{item.get('file', '')}:{item.get('line', 0)}"
+        lines.append(
+            "| {id} | {pos} | {typ} | {sev} | {desc} | {fix} | {score}/10 |".format(
+                id=item.get("bucket_id", "-"),
+                pos=position,
+                typ=item.get("primary_type", "unknown"),
+                sev=severity,
+                desc=desc,
+                fix=fix,
+                score=item.get("consensus_strength", 0.0),
+            )
+        )
+
+    text = "\n".join(lines) + "\n"
+    if args.output:
+        with open(args.output, "w", encoding="utf-8") as f:
+            f.write(text)
+    else:
+        sys.stdout.write(text)
+    return 0
+
+
+if __name__ == "__main__":
+    raise SystemExit(main())
diff --git a/user/apps/c_unitest/test_cgroup_mvp_ns_clone.c b/user/apps/c_unitest/test_cgroup_mvp_ns_clone.c
new file mode 100644
index 00000000..77e7b78a
--- /dev/null
+++ b/user/apps/c_unitest/test_cgroup_mvp_ns_clone.c
@@ -0,0 +1,277 @@
+#define _GNU_SOURCE
+
+#include <errno.h>
+#include <fcntl.h>
+#include <sched.h>
+#include <signal.h>
+#include <stdint.h>
+#include <stdio.h>
+#include <stdlib.h>
+#include <string.h>
+#include <sys/stat.h>
+#include <sys/syscall.h>
+#include <sys/types.h>
+#include <sys/wait.h>
+#include <unistd.h>
+
+#ifndef SYS_clone3
+#define SYS_clone3 435
+#endif
+
+#ifndef CLONE_NEWCGROUP
+#define CLONE_NEWCGROUP 0x02000000
+#endif
+
+#ifndef CLONE_INTO_CGROUP
+#define CLONE_INTO_CGROUP 0x200000000ULL
+#endif
+
+/*
+ * 本测试覆盖 cgroup v2 MVP 中 namespace 与 clone3 的联动路径：
+ * 1) unshare(CLONE_NEWCGROUP) 后 /proc/self/cgroup 视图根发生变化。
+ * 2) setns() 可以切回旧的 cgroup namespace。
+ * 3) clone3(CLONE_INTO_CGROUP) 覆盖 bad-fd 与成功路径。
+ * 4) 在不同 cgroup namespace 下，sibling 视图路径投影符合预期。
+ */
+
+struct clone_args_local {
+    uint64_t flags;
+    uint64_t pidfd;
+    uint64_t child_tid;
+    uint64_t parent_tid;
+    uint64_t exit_signal;
+    uint64_t stack;
+    uint64_t stack_size;
+    uint64_t tls;
+    uint64_t set_tid;
+    uint64_t set_tid_size;
+    uint64_t cgroup;
+};
+
+static void fail(const char *step) {
+    printf("[FAIL] %s: %s\n", step, strerror(errno));
+    exit(1);
+}
+
+static int ensure_dir(const char *path) {
+    if (mkdir(path, 0755) == 0) {
+        return 0;
+    }
+    if (errno == EEXIST) {
+        return 0;
+    }
+    return -1;
+}
+
+static int write_text(const char *path, const char *text) {
+    int fd = open(path, O_WRONLY);
+    ssize_t n;
+    if (fd < 0) {
+        return -1;
+    }
+    n = write(fd, text, strlen(text));
+    close(fd);
+    return n == (ssize_t)strlen(text) ? 0 : -1;
+}
+
+static int read_text(const char *path, char *buf, size_t len) {
+    int fd = open(path, O_RDONLY);
+    ssize_t n;
+    if (fd < 0) {
+        return -1;
+    }
+    n = read(fd, buf, len - 1);
+    close(fd);
+    if (n < 0) {
+        return -1;
+    }
+    buf[n] = '\0';
+    return 0;
+}
+
+static void run_unshare_setns_case(void) {
+    const char *grp = "/sys/fs/cgroup/mvp_setns_combo";
+    const char *procs = "/sys/fs/cgroup/mvp_setns_combo/cgroup.procs";
+    int old_ns_fd;
+    char buf[256];
+
+    if (ensure_dir(grp) != 0) {
+        fail("mkdir mvp_setns_combo");
+    }
+    if (write_text(procs, "0\n") != 0) {
+        fail("move self to mvp_setns_combo");
+    }
+
+    old_ns_fd = open("/proc/self/ns/cgroup", O_RDONLY);
+    if (old_ns_fd < 0) {
+        fail("open old cgroup ns fd");
+    }
+
+    if (unshare(CLONE_NEWCGROUP) != 0) {
+        close(old_ns_fd);
+        fail("unshare CLONE_NEWCGROUP");
+    }
+
+    if (read_text("/proc/self/cgroup", buf, sizeof(buf)) != 0) {
+        close(old_ns_fd);
+        fail("read /proc/self/cgroup after unshare");
+    }
+    if (strstr(buf, "0::/") == NULL) {
+        printf("[FAIL] unexpected after unshare: %s\n", buf);
+        close(old_ns_fd);
+        exit(1);
+    }
+
+    if (setns(old_ns_fd, CLONE_NEWCGROUP) != 0) {
+        close(old_ns_fd);
+        fail("setns back to old cgroup ns");
+    }
+    close(old_ns_fd);
+
+    if (read_text("/proc/self/cgroup", buf, sizeof(buf)) != 0) {
+        fail("read /proc/self/cgroup after setns");
+    }
+    if (strstr(buf, "0::/mvp_setns_combo") == NULL) {
+        printf("[FAIL] unexpected after setns: %s\n", buf);
+        exit(1);
+    }
+}
+
+static void run_clone3_into_cgroup_case(void) {
+    const char *grp = "/sys/fs/cgroup/mvp_clone3_combo";
+    int cgfd;
+    struct clone_args_local bad = {0};
+    struct clone_args_local good = {0};
+    long ret;
+    long child;
+    int status = 0;
+
+    if (ensure_dir(grp) != 0) {
+        fail("mkdir mvp_clone3_combo");
+    }
+    cgfd = open(grp, O_RDONLY | O_DIRECTORY);
+    if (cgfd < 0) {
+        fail("open mvp_clone3_combo");
+    }
+
+    bad.flags = CLONE_INTO_CGROUP;
+    bad.exit_signal = SIGCHLD;
+    bad.cgroup = (uint64_t)123456;
+    ret = syscall(SYS_clone3, &bad, sizeof(bad));
+    if (ret != -1 || errno != EBADF) {
+        printf("[FAIL] clone3 bad-fd path: ret=%ld errno=%d\n", ret, errno);
+        close(cgfd);
+        exit(1);
+    }
+
+    good.flags = CLONE_INTO_CGROUP;
+    good.exit_signal = SIGCHLD;
+    good.cgroup = (uint64_t)cgfd;
+    child = syscall(SYS_clone3, &good, sizeof(good));
+    if (child < 0) {
+        close(cgfd);
+        fail("clone3 into cgroup");
+    }
+    if (child == 0) {
+        char cgbuf[256];
+        if (read_text("/proc/self/cgroup", cgbuf, sizeof(cgbuf)) != 0) {
+            _exit(2);
+        }
+        if (strstr(cgbuf, "0::/mvp_clone3_combo") == NULL) {
+            _exit(3);
+        }
+        _exit(0);
+    }
+
+    if (waitpid((pid_t)child, &status, 0) < 0) {
+        close(cgfd);
+        fail("waitpid clone3 child");
+    }
+    close(cgfd);
+
+    if (!WIFEXITED(status) || WEXITSTATUS(status) != 0) {
+        printf("[FAIL] clone3 child status=0x%x\n", status);
+        exit(1);
+    }
+}
+
+static void run_sibling_view_case(void) {
+    const char *ga = "/sys/fs/cgroup/mvp_view_a_combo";
+    const char *gb = "/sys/fs/cgroup/mvp_view_b_combo";
+    const char *pa = "/sys/fs/cgroup/mvp_view_a_combo/cgroup.procs";
+    const char *pb = "/sys/fs/cgroup/mvp_view_b_combo/cgroup.procs";
+    int pipefd[2];
+    pid_t pid;
+    char ok = 0;
+    char path[64];
+    char buf[256];
+
+    if (ensure_dir(ga) != 0 || ensure_dir(gb) != 0) {
+        fail("mkdir sibling cgroups");
+    }
+    if (write_text(pa, "0\n") != 0) {
+        fail("move parent to mvp_view_a_combo");
+    }
+
+    if (pipe(pipefd) != 0) {
+        fail("pipe for sibling case");
+    }
+
+    pid = fork();
+    if (pid < 0) {
+        fail("fork sibling child");
+    }
+    if (pid == 0) {
+        close(pipefd[0]);
+        if (write_text(pb, "0\n") != 0) {
+            _exit(2);
+        }
+        ok = '1';
+        if (write(pipefd[1], &ok, 1) != 1) {
+            _exit(3);
+        }
+        close(pipefd[1]);
+        pause();
+        _exit(0);
+    }
+
+    close(pipefd[1]);
+    if (read(pipefd[0], &ok, 1) != 1 || ok != '1') {
+        close(pipefd[0]);
+        kill(pid, SIGKILL);
+        waitpid(pid, NULL, 0);
+        printf("[FAIL] sibling child setup failed\n");
+        exit(1);
+    }
+    close(pipefd[0]);
+
+    if (unshare(CLONE_NEWCGROUP) != 0) {
+        kill(pid, SIGKILL);
+        waitpid(pid, NULL, 0);
+        fail("unshare before sibling proc view check");
+    }
+
+    snprintf(path, sizeof(path), "/proc/%d/cgroup", (int)pid);
+    if (read_text(path, buf, sizeof(buf)) != 0) {
+        kill(pid, SIGKILL);
+        waitpid(pid, NULL, 0);
+        fail("read sibling /proc/<pid>/cgroup");
+    }
+    if (strstr(buf, "0::/../mvp_view_b_combo") == NULL) {
+        printf("[FAIL] unexpected sibling projection: %s\n", buf);
+        kill(pid, SIGKILL);
+        waitpid(pid, NULL, 0);
+        exit(1);
+    }
+
+    kill(pid, SIGKILL);
+    waitpid(pid, NULL, 0);
+}
+
+int main(void) {
+    run_unshare_setns_case();
+    run_clone3_into_cgroup_case();
+    run_sibling_view_case();
+    printf("[PASS] cgroup_mvp_ns_clone\n");
+    return 0;
+}
