+            let root_inode = ProcessManager::current_mntns().root_inode();
+            let sys = root_inode.find("sys")?;
+            let fs_dir = ensure_dir(&sys, "fs", InodeMode::from_bits_truncate(0o755))?;
+            let cgroup_dir = ensure_dir(&fs_dir, "cgroup", InodeMode::from_bits_truncate(0o755))?;
+
+            let cgroup_fs = Cgroup2Fs::new(cgroup_root().root(), false);
+            let mntfs = cgroup_dir.mount(
+                cgroup_fs,
+                crate::filesystem::vfs::mount::MountFlags::empty(),
+            )?;
+            let root_ino = root_inode.metadata()?.inode_id;
+            ProcessManager::current_mntns().add_mount(
+                Some(root_ino),
+                Arc::new(MountPath::from("/sys/fs/cgroup")),
+                mntfs,
+            )?;
+
+            ::log::info!("Cgroup2 mounted at /sys/fs/cgroup");
+            Ok(())
+        })());
+    });
+    result.unwrap_or(Ok(()))
+}
+
+fn ensure_dir(
+    parent: &Arc<dyn IndexNode>,
+    name: &str,
+    mode: InodeMode,
+) -> Result<Arc<dyn IndexNode>, SystemError> {
+    if let Ok(inode) = parent.find(name) {
+        return Ok(inode);
+    }
+
+    if let Some(kernfs_parent) = parent.as_any_ref().downcast_ref::<KernFSInode>() {
+        return match kernfs_parent.add_dir(name.to_string(), mode, None, None) {
+            Ok(inode) => Ok(inode),
+            Err(SystemError::EEXIST) => parent.find(name),
+            Err(e) => Err(e),
+        };
+    }
+
+    match parent.mkdir(name, mode) {
+        Ok(inode) => Ok(inode),
+        Err(SystemError::EEXIST) => parent.find(name),
+        Err(e) => Err(e),
+    }
+}
+
+impl Cgroup2Inode {
+    fn cgroup_of_dir(inode: &Arc<Cgroup2Inode>) -> Option<Arc<CgroupNode>> {
+        let inner = inode.inner.lock();
+        match &inner.kind {
+            Cgroup2InodeKind::Dir { cgroup, .. } => Some(cgroup.clone()),
+            _ => None,
+        }
+    }
+
+    fn fs_root_cgroup(fs_root: &Arc<dyn IndexNode>) -> Result<Arc<CgroupNode>, SystemError> {
+        let root_inode = fs_root
+            .as_any_ref()
+            .downcast_ref::<Cgroup2Inode>()
+            .ok_or(SystemError::EINVAL)?;
+        let inner = root_inode.inner.lock();
+        match &inner.kind {
+            Cgroup2InodeKind::Dir { cgroup, .. } => Ok(cgroup.clone()),
+            _ => Err(SystemError::EINVAL),
+        }
+    }
+
+    fn prune_stale_dir_cache(parent: &Arc<Cgroup2Inode>) -> Result<(), SystemError> {
+        let (parent_cgroup, entries) = {
+            let inner = parent.inner.lock();
+            match &inner.kind {
+                // 先获取 parent cgroup 和缓存的 entries，避免长时间持有锁。
+                Cgroup2InodeKind::Dir { cgroup, children } => {
+                    let entries = children
+                        .iter()
+                        .map(|(name, inode)| (name.clone(), inode.clone()))
+                        .collect::<Vec<_>>();
+                    (cgroup.clone(), entries)
+                }
+                _ => return Err(SystemError::ENOTDIR),
+            }
+        };
+
+        let mut stale = Vec::new();
+        for (name, inode) in entries {
+            let Some(cached_cgroup) = Self::cgroup_of_dir(&inode) else {
+                continue;
+            };
+            match parent_cgroup.child(&name) {
+                Some(real) if Arc::ptr_eq(&real, &cached_cgroup) => {}
+                _ => stale.push(name),
+            }
+        }
+
+        if stale.is_empty() {
+            return Ok(());
+        }
+
+        let mut inner = parent.inner.lock();
+        if let Cgroup2InodeKind::Dir { children, .. } = &mut inner.kind {
+            for name in stale {
+                children.remove(&name);
+            }
+            return Ok(());
+        }
+
+        Err(SystemError::ENOTDIR)
+    }
+    //把全局cgroup node路径转换为fs内路径，并找到对应inode
+    fn find_cgroup_dir_from_fs_root(
+        fs_root: Arc<dyn IndexNode>,
+        cgroup: &Arc<CgroupNode>,
+    ) -> Result<Arc<dyn IndexNode>, SystemError> {
+        let view_root = Self::fs_root_cgroup(&fs_root)?;
+        if !view_root.is_ancestor_of(cgroup) {
+            return Err(SystemError::ENOENT);
+        }
+        let rel = crate::cgroup::cgroup_path_relative_to_node(cgroup, &view_root);
+        if rel == "/" {
+            return Ok(fs_root);
+        }
+
+        let mut cur = fs_root;
+        for comp in rel.trim_start_matches('/').split('/') {
+            if comp.is_empty() {
+                continue;
+            }
+            if comp == ".." {
+                return Err(SystemError::ENOENT);
+            }
+            cur = cur.find(comp)?;
+        }
+        Ok(cur)
+    }
+
+    fn cgroup_procs_inode_from_fs_root(
+        fs_root: Arc<dyn IndexNode>,
+        cgroup: &Arc<CgroupNode>,
+    ) -> Result<Arc<dyn IndexNode>, SystemError> {
+        let dir = Self::find_cgroup_dir_from_fs_root(fs_root, cgroup)?;
+        dir.find("cgroup.procs")
+    }
+
+    fn check_attach_permissions(
+        fs_root: Arc<dyn IndexNode>,
+        src_cgroup: &Arc<CgroupNode>,
+        dst_cgroup: &Arc<CgroupNode>,
+    ) -> Result<(), SystemError> {
+        let current = ProcessManager::current_pcb();
+        let cred = current.cred();
+        //目标cgroup的procs可写
+        let dst_procs = Self::cgroup_procs_inode_from_fs_root(fs_root.clone(), dst_cgroup)?;
+        let dst_md = dst_procs.metadata()?;
+        cred.inode_permission(&dst_md, PermissionMask::MAY_WRITE.bits())
+            .map_err(|_| SystemError::EACCES)?;
+        //共同祖先的procs可写
+        let common = cgroup_common_ancestor(src_cgroup, dst_cgroup);
+        let common_procs = Self::cgroup_procs_inode_from_fs_root(fs_root, &common)?;
+        let common_md = common_procs.metadata()?;
+        cred.inode_permission(&common_md, PermissionMask::MAY_WRITE.bits())
+            .map_err(|_| SystemError::EACCES)?;
+
+        Ok(())
+    }
+
+    fn available_controllers_for(cgroup: &Arc<CgroupNode>) -> Vec<&'static str> {
+        let Some(parent) = cgroup.parent() else {
+            return AVAILABLE_CONTROLLERS.to_vec();
+        };
+        let parent_enabled: HashSet<String> = parent.subtree_control().into_iter().collect();
+        AVAILABLE_CONTROLLERS
+            .iter()
+            .copied()
+            .filter(|name| parent_enabled.contains(*name))
+            .collect()
+    }
+
+    fn encode_controller_list(items: &[String]) -> Vec<u8> {
+        if items.is_empty() {
+            return b"\n".to_vec();
+        }
+        let mut sorted = items.to_vec();
+        sorted.sort();
+        let mut line = sorted.join(" ");
+        line.push('\n');
+        line.into_bytes()
+    }
+
+    fn parse_subtree_control_ops(input: &str) -> Result<Vec<(bool, &str)>, SystemError> {
+        let trimmed = input.trim();
+        if trimmed.is_empty() {
+            return Ok(Vec::new());
+        }
+
+        let mut ops = Vec::new();
+        for token in trimmed.split_whitespace() {
+            let mut chars = token.chars();
+            let op = chars.next().ok_or(SystemError::EINVAL)?;
+            let enable = match op {
+                '+' => true,
+                '-' => false,
+                _ => return Err(SystemError::EINVAL),
+            };
+            let name = chars.as_str();
+            if name.is_empty() || name.contains('/') {
+                return Err(SystemError::EINVAL);
+            }
+            ops.push((enable, name));
+        }
+        Ok(ops)
+    }
+
+    fn encode_pids_max(limit: Option<usize>) -> Vec<u8> {
+        match limit {
+            Some(v) => format!("{}\n", v).into_bytes(),
+            None => b"max\n".to_vec(),
+        }
+    }
+
+    fn parse_pids_max(input: &str) -> Result<Option<usize>, SystemError> {
+        let trimmed = input.trim();
+        if trimmed == "max" {
+            return Ok(None);
+        }
+        let value = trimmed.parse::<u64>().map_err(|_| SystemError::EINVAL)?;
+        let value = usize::try_from(value).map_err(|_| SystemError::EINVAL)?;
+        Ok(Some(value))
+    }
+
+    fn validate_enable_controller(cgroup: &Arc<CgroupNode>, name: &str) -> Result<(), SystemError> {
+        let available = Self::available_controllers_for(cgroup);
+        if !available.iter().any(|c| *c == name) {
+            return Err(SystemError::EINVAL);
+        }
+
+        // no-internal-process 框架：仅对 domain controller 生效。
+        // 当前阶段未启用 controller，DOMAIN_CONTROLLERS 为空，不会误拒绝。
+        if DOMAIN_CONTROLLERS.iter().any(|c| *c == name)
+            && cgroup.has_tasks()
+            && cgroup.has_children()
+        {
+            return Err(SystemError::EBUSY);
+        }
+        Ok(())
+    }
+
+    fn apply_subtree_control(
+        cgroup: &Arc<CgroupNode>,
+        input: &str,
+    ) -> Result<Vec<u8>, SystemError> {
+        let ops = Self::parse_subtree_control_ops(input)?;
+        let mut enabled: HashSet<String> = cgroup.subtree_control().into_iter().collect();
+
+        for (is_enable, name) in ops {
+            if is_enable {
+                Self::validate_enable_controller(cgroup, name)?;
+                enabled.insert(name.to_string());
+            } else {
+                for child in cgroup.children() {
+                    if child.subtree_control().iter().any(|ctrl| ctrl == name) {
+                        return Err(SystemError::EBUSY);
+                    }
+                }
+                enabled.remove(name);
+            }
+        }
+
+        cgroup.set_subtree_control(enabled.clone());
+        let mut out: Vec<String> = enabled.into_iter().collect();
+        out.sort();
+        Ok(Self::encode_controller_list(&out))
+    }
+
+    fn new_dir(name: String, cgroup: Arc<CgroupNode>) -> Arc<Self> {
+        Arc::new_cyclic(|weak| Self {
+            self_ref: weak.clone(),
+            fs: RwSem::new(Weak::new()),
+            inner: SpinLock::new(Cgroup2InodeInner {
+                parent: Weak::new(),
+                metadata: Metadata {
+                    size: 0,
+                    mode: InodeMode::from_bits_truncate(0o755),
+                    uid: 0,
+                    gid: 0,
+                    blk_size: CGROUP2_BLOCK_SIZE as usize,
+                    blocks: 0,
+                    atime: PosixTimeSpec::default(),
+                    mtime: PosixTimeSpec::default(),
+                    ctime: PosixTimeSpec::default(),
+                    btime: PosixTimeSpec::default(),
+                    dev_id: 0,
+                    inode_id: generate_inode_id(),
+                    file_type: FileType::Dir,
+                    nlinks: 2,
+                    raw_dev: Default::default(),
+                    flags: InodeFlags::empty(),
+                },
+                name,
+                kind: Cgroup2InodeKind::Dir {
+                    cgroup,
+                    children: HashMap::new(),
+                },
+            }),
+        })
+    }
+
+    fn new_file(
+        name: String,
+        cgroup: Arc<CgroupNode>,
+        ty: CgroupCoreFile,
+        init: &[u8],
+    ) -> Arc<Self> {
+        Arc::new_cyclic(|weak| Self {
+            self_ref: weak.clone(),
+            fs: RwSem::new(Weak::new()),
+            inner: SpinLock::new(Cgroup2InodeInner {
+                parent: Weak::new(),
+                metadata: Metadata {
+                    size: init.len() as i64,
+                    mode: InodeMode::from_bits_truncate(0o644),
+                    uid: 0,
+                    gid: 0,
+                    blk_size: CGROUP2_BLOCK_SIZE as usize,
+                    blocks: 0,
+                    atime: PosixTimeSpec::default(),
+                    mtime: PosixTimeSpec::default(),
+                    ctime: PosixTimeSpec::default(),
+                    btime: PosixTimeSpec::default(),
+                    dev_id: 0,
+                    inode_id: generate_inode_id(),
+                    file_type: FileType::File,
+                    nlinks: 1,
+                    raw_dev: Default::default(),
+                    flags: InodeFlags::empty(),
+                },
+                name,
+                kind: Cgroup2InodeKind::File {
+                    cgroup,
+                    ty,
+                    data: init.to_vec(),
+                },
+            }),
+        })
+    }
+
+    fn add_child(
+        parent: &Arc<Cgroup2Inode>,
+        name: &str,
+        child: Arc<Cgroup2Inode>,
+    ) -> Result<(), SystemError> {
+        let fs_weak = parent.fs.read().clone();
+        *child.fs.write() = fs_weak;
+        child.inner.lock().parent = Arc::downgrade(parent);
+
+        let mut inner = parent.inner.lock();
+        match &mut inner.kind {
+            Cgroup2InodeKind::Dir { children, .. } => {
+                children.insert(name.to_string(), child);
+                Ok(())
+            }
+            _ => Err(SystemError::ENOTDIR),
+        }
+    }
+
+    fn lookup_child(
+        parent: &Arc<Cgroup2Inode>,
+        name: &str,
+    ) -> Result<Arc<Cgroup2Inode>, SystemError> {
+        if name == "." {
+            return Ok(parent.clone());
+        }
+        if name == ".." {
+            return Ok(parent
+                .inner
+                .lock()
+                .parent
+                .upgrade()
+                .unwrap_or_else(|| parent.clone()));
+        }
+
+        Self::prune_stale_dir_cache(parent)?;
+
+        {
+            let inner = parent.inner.lock();
+            match &inner.kind {
+                Cgroup2InodeKind::Dir { children, .. } => {
+                    if let Some(inode) = children.get(name).cloned() {
+                        return Ok(inode);
+                    }
+                }
+                _ => return Err(SystemError::ENOTDIR),
+            }
+        }
+
+        let parent_cgroup = {
+            let inner = parent.inner.lock();
+            match &inner.kind {
+                Cgroup2InodeKind::Dir { cgroup, .. } => cgroup.clone(),
+                _ => return Err(SystemError::ENOTDIR),
+            }
+        };
+
+        let child_cgroup = parent_cgroup.child(name).ok_or(SystemError::ENOENT)?;
+        let child = Cgroup2Inode::new_dir(name.to_string(), child_cgroup);
+        Cgroup2Inode::add_child(parent, name, child.clone())?;
+        Cgroup2Inode::populate_core_files(&child)?;
+        //以父目录当前缓存为准
+        let inner = parent.inner.lock();
+        match &inner.kind {
+            Cgroup2InodeKind::Dir { children, .. } => {
+                children.get(name).cloned().ok_or(SystemError::ENOENT)
+            }
+            _ => Err(SystemError::ENOTDIR),
+        }
+    }
+
+    fn populate_core_files(dir: &Arc<Cgroup2Inode>) -> Result<(), SystemError> {
+        let cgroup = {
+            let inner = dir.inner.lock();
+            match &inner.kind {
+                Cgroup2InodeKind::Dir { cgroup, .. } => cgroup.clone(),
+                _ => return Err(SystemError::ENOTDIR),
+            }
+        };
+
+        let base_files = [
+            ("cgroup.procs", CgroupCoreFile::Procs, b"".as_slice()),
+            (
+                "cgroup.controllers",
+                CgroupCoreFile::Controllers,
+                b"\n".as_slice(),
+            ),
+            (
+                "cgroup.subtree_control",
+                CgroupCoreFile::SubtreeControl,
+                b"\n".as_slice(),
+            ),
+        ];
+        for (name, ty, init) in base_files {
+            let file = Cgroup2Inode::new_file(name.to_string(), cgroup.clone(), ty, init);
+            Self::add_child(dir, name, file)?;
+        }
+
+        if cgroup.parent().is_some() {
+            let pids_files = [
+                (
+                    "pids.current",
+                    CgroupCoreFile::PidsCurrent,
+                    //初始内容占位
+                    b"0\n".as_slice(),
+                ),
+                ("pids.max", CgroupCoreFile::PidsMax, b"max\n".as_slice()),
+                (
+                    "pids.events",
+                    CgroupCoreFile::PidsEvents,
+                    b"max 0\n".as_slice(),
+                ),
+            ];
+            for (name, ty, init) in pids_files {
+                let file = Cgroup2Inode::new_file(name.to_string(), cgroup.clone(), ty, init);
+                Self::add_child(dir, name, file)?;
+            }
+        }
+
+        // Linux 语义：cgroup.type/cgroup.events 仅存在于 non-root cgroup。
+        if cgroup.parent().is_some() {
+            let extra_files = [
+                ("cgroup.events", CgroupCoreFile::Events, b"".as_slice()),
+                ("cgroup.type", CgroupCoreFile::Type, b"domain\n".as_slice()),
+            ];
+            for (name, ty, init) in extra_files {
+                let file = Cgroup2Inode::new_file(name.to_string(), cgroup.clone(), ty, init);
+                Self::add_child(dir, name, file)?;
+            }
+        }
+
+        Ok(())
+    }
+
+    fn is_populated(cgroup: &Arc<CgroupNode>) -> bool {
+        if cgroup.has_tasks() {
+            return true;
+        }
+        let root = cgroup_root();
+        for child_name in cgroup.children_names() {
+            let mut path = crate::cgroup::cgroup_path_relative_to_node(cgroup, &root.root());
+            if path == "/" {
+                path = format!("/{}", child_name);
+            } else {
+                path = format!("{}/{}", path, child_name);
+            }
+            if let Ok(node) = crate::cgroup::find_node_by_abs_path(&path) {
+                if Self::is_populated(&node) {
+                    return true;
+                }
+            }
+        }
+        false
+    }
+
+    fn read_file(
+        inner: &mut Cgroup2InodeInner,
+        offset: usize,
+        len: usize,
+        buf: &mut [u8],
+    ) -> Result<usize, SystemError> {
+        let bytes = match &mut inner.kind {
+            Cgroup2InodeKind::File {
+                cgroup,
+                ty,
+                data: _,
+            } => match ty {
+                CgroupCoreFile::Procs => {
+                    let mut lines = String::new();
+                    for pid in cgroup.tasks() {
+                        lines.push_str(&format!("{}\n", pid.data()));
+                    }
+                    lines.into_bytes()
+                }
+                CgroupCoreFile::Controllers => {
+                    let items: Vec<String> = Self::available_controllers_for(cgroup)
+                        .into_iter()
+                        .map(|s| s.to_string())
+                        .collect();
+                    Self::encode_controller_list(&items)
+                }
+                CgroupCoreFile::SubtreeControl => {
+                    let items = cgroup.subtree_control();
+                    Self::encode_controller_list(&items)
+                }
+                CgroupCoreFile::Events => {
+                    let populated = if Self::is_populated(cgroup) { 1 } else { 0 };
+                    format!("populated {}\nfrozen 0\n", populated).into_bytes()
+                }
+                CgroupCoreFile::Type => b"domain\n".to_vec(),
+                CgroupCoreFile::PidsCurrent => {
+                    format!("{}\n", cgroup.subtree_task_count()).into_bytes()
+                }
+                CgroupCoreFile::PidsMax => Self::encode_pids_max(cgroup.pids_max()),
+                CgroupCoreFile::PidsEvents => {
+                    format!("max {}\n", cgroup.pids_events_max()).into_bytes()
+                }
+            },
+            _ => return Err(SystemError::EISDIR),
+        };
+
+        let start = core::cmp::min(offset, bytes.len());
+        let end = core::cmp::min(offset + len, bytes.len());
+        let n = end.saturating_sub(start);
+        if n > buf.len() {
+            return Err(SystemError::ENOBUFS);
+        }
+        buf[..n].copy_from_slice(&bytes[start..end]);
+        Ok(n)
+    }
+
+    fn write_file(
+        this: &Arc<Cgroup2Inode>,
+        inner: &mut Cgroup2InodeInner,
+        offset: usize,
+        buf: &[u8],
+    ) -> Result<usize, SystemError> {
+        match &mut inner.kind {
+            Cgroup2InodeKind::File { cgroup, ty, data } => match ty {
+                CgroupCoreFile::Procs => {
+                    if offset != 0 {
+                        return Err(SystemError::EINVAL);
+                    }
+                    let input = core::str::from_utf8(buf).map_err(|_| SystemError::EINVAL)?;
+                    let pid_str = input.trim();
+                    let current = ProcessManager::current_pcb();
+                    let task = if pid_str == "0" {
+                        current.clone()
+                    } else {
+                        let pid_num = pid_str.parse::<usize>().map_err(|_| SystemError::EINVAL)?;
+                        ProcessManager::find_task_by_vpid(crate::process::RawPid::new(pid_num))
+                            .ok_or(SystemError::ESRCH)?
+                    };
+                    let src = task.task_cgroup_node();
+                    let fs_nsdelegate = this
+                        .fs()
+                        .as_any_ref()
+                        .downcast_ref::<Cgroup2Fs>()
+                        .map(|fs| fs.nsdelegate())
+                        .unwrap_or(false);
+                    if fs_nsdelegate {
+                        let ns_root = current.nsproxy().cgroup_ns.root_cgroup().clone();
+                        if !ns_root.is_ancestor_of(cgroup) {
+                            return Err(SystemError::ENOENT);
+                        }
+                        if !ns_root.is_ancestor_of(&src) {
+                            return Err(SystemError::ENOENT);
+                        }
+                    }
+                    if Arc::ptr_eq(&src, cgroup) {
+                        return Ok(buf.len());
+                    }
+                    Self::check_attach_permissions(this.fs().root_inode(), &src, cgroup)?;
+                    let leader = {
+                        let ti = task.threads_read_irqsave();
+                        ti.group_leader().unwrap_or_else(|| task.clone())
+                    };
+                    let others = leader.threads_read_irqsave().group_tasks_clone();
+
+                    let mut to_move = Vec::new();
+                    if !leader.is_exited() {
+                        to_move.push(leader.clone());
+                    }
+                    for weak in others {
+                        if let Some(t) = weak.upgrade() {
+                            if !t.is_exited() {
+                                to_move.push(t);
+                            }
+                        }
+                    }
+                    if to_move.is_empty() {
+                        return Err(SystemError::ESRCH);
+                    }
+                    let moved_tasks = to_move.len();
+
+                    let _cgroup_guard = cgroup_accounting_lock().lock();
+                    cgroup_migrate_vet_dst_with_src(&src, cgroup, moved_tasks)?;
+
+                    for t in to_move {
+                        t.set_task_cgroup_node(cgroup.clone());
+                    }
+                    Ok(buf.len())
+                }
+                CgroupCoreFile::SubtreeControl => {
+                    if offset != 0 {
+                        return Err(SystemError::EINVAL);
+                    }
+                    let input = core::str::from_utf8(buf).map_err(|_| SystemError::EINVAL)?;
+                    if !ProcessManager::current_pcb().cred().has_cap_sys_admin() {
+                        return Err(SystemError::EPERM);
+                    }
+                    let new_data = Self::apply_subtree_control(cgroup, input)?;
+                    data.clear();
+                    data.extend_from_slice(&new_data);
+                    inner.metadata.size = data.len() as i64;
+                    Ok(buf.len())
+                }
+                CgroupCoreFile::PidsMax => {
+                    if offset != 0 {
+                        return Err(SystemError::EINVAL);
+                    }
+                    let input = core::str::from_utf8(buf).map_err(|_| SystemError::EINVAL)?;
+                    let new_limit = Self::parse_pids_max(input)?;
+                    cgroup.set_pids_max(new_limit);
+                    let new_data = Self::encode_pids_max(new_limit);
+                    data.clear();
+                    data.extend_from_slice(&new_data);
+                    inner.metadata.size = data.len() as i64;
+                    Ok(buf.len())
+                }
+                CgroupCoreFile::Controllers
+                | CgroupCoreFile::Events
+                | CgroupCoreFile::Type
+                | CgroupCoreFile::PidsCurrent
+                | CgroupCoreFile::PidsEvents => Err(SystemError::EINVAL),
+            },
+            _ => Err(SystemError::EISDIR),
+        }
+    }
+}
+
+pub fn cgroup2_check_attach_permissions(
+    fs_root: Arc<dyn IndexNode>,
+    src_cgroup: &Arc<CgroupNode>,
+    dst_cgroup: &Arc<CgroupNode>,
+) -> Result<(), SystemError> {
+    Cgroup2Inode::check_attach_permissions(fs_root, src_cgroup, dst_cgroup)
+}
+//转换inode为cgroup node
+pub fn cgroup2_inode_to_node(inode: &Arc<dyn IndexNode>) -> Result<Arc<CgroupNode>, SystemError> {
+    let cgroup_inode = inode
+        .as_any_ref()
+        .downcast_ref::<Cgroup2Inode>()
+        .ok_or(SystemError::EINVAL)?;
+    let inner = cgroup_inode.inner.lock();
+    match &inner.kind {
+        Cgroup2InodeKind::Dir { cgroup, .. } => Ok(cgroup.clone()),
+        _ => Err(SystemError::ENOTDIR),
+    }
+}
+
+impl FileSystem for Cgroup2Fs {
+    fn root_inode(&self) -> Arc<dyn IndexNode> {
+        self.root_inode.clone()
+    }
+
+    fn info(&self) -> FsInfo {
+        FsInfo {
+            blk_dev_id: 0,
+            max_name_len: CGROUP2_MAX_NAMELEN,
+        }
+    }
+
+    fn as_any_ref(&self) -> &dyn Any {
+        self
+    }
+
+    fn name(&self) -> &str {
+        "cgroup2"
+    }
+
+    fn super_block(&self) -> SuperBlock {
+        SuperBlock::new(
+            Magic::CGROUP2_SUPER_MAGIC,
+            CGROUP2_BLOCK_SIZE,
+            CGROUP2_MAX_NAMELEN as u64,
+        )
+    }
+}
+
+impl MountableFileSystem for Cgroup2Fs {
+    fn make_mount_data(
+        raw_data: Option<&str>,
+        _source: &str,
+    ) -> Result<Option<Arc<dyn FileSystemMakerData + 'static>>, SystemError> {
+        let mut nsdelegate = false;
+        if let Some(opts) = raw_data {
+            for raw in opts.split(',') {
+                let token = raw.trim();
+                if token.is_empty() {
+                    continue;
+                }
+                match token {
+                    "nsdelegate" => nsdelegate = true,
+                    "nsdelegate=0" => nsdelegate = false,
+                    "nsdelegate=1" => nsdelegate = true,
+                    _ => return Err(SystemError::EINVAL),
+                }
+            }
+        }
+
+        let root_cgroup = ProcessManager::current_pcb()
+            .nsproxy()
+            .cgroup_ns
+            .root_cgroup()
+            .clone();
+        Ok(Some(Arc::new(Cgroup2MountData {
+            root_cgroup,
+            nsdelegate,
+        })))
+    }
+
+    fn make_fs(
+        data: Option<&dyn FileSystemMakerData>,
+    ) -> Result<Arc<dyn FileSystem + 'static>, SystemError> {
+        let mount_data = data.and_then(|d| d.as_any().downcast_ref::<Cgroup2MountData>());
+        let root_cgroup = mount_data
+            .map(|d| d.root_cgroup.clone())
+            .unwrap_or_else(|| cgroup_root().root());
+        let nsdelegate = mount_data.map(|d| d.nsdelegate).unwrap_or(false);
+        Ok(Cgroup2Fs::new(root_cgroup, nsdelegate))
+    }
+}
+
+impl IndexNode for Cgroup2Inode {
+    fn open(
+        &self,
+        _data: MutexGuard<FilePrivateData>,
+        _flags: &FileFlags,
+    ) -> Result<(), SystemError> {
+        Ok(())
+    }
+
+    fn close(&self, _data: MutexGuard<FilePrivateData>) -> Result<(), SystemError> {
+        Ok(())
+    }
+
+    fn read_at(
+        &self,
+        offset: usize,
+        len: usize,
+        buf: &mut [u8],
+        _data: MutexGuard<FilePrivateData>,
+    ) -> Result<usize, SystemError> {
+        let mut inner = self.inner.lock();
+        Cgroup2Inode::read_file(&mut inner, offset, len, buf)
+    }
+
+    fn write_at(
+        &self,
+        offset: usize,
+        len: usize,
+        buf: &[u8],
+        _data: MutexGuard<FilePrivateData>,
+    ) -> Result<usize, SystemError> {
+        let n = core::cmp::min(len, buf.len());
+        let this = self.self_ref.upgrade().unwrap();
+        let mut inner = self.inner.lock();
+        Cgroup2Inode::write_file(&this, &mut inner, offset, &buf[..n])
+    }
+
+    fn metadata(&self) -> Result<Metadata, SystemError> {
+        Ok(self.inner.lock().metadata.clone())
+    }
+
+    fn set_metadata(&self, metadata: &Metadata) -> Result<(), SystemError> {
+        self.inner.lock().metadata = metadata.clone();
+        Ok(())
+    }
+
+    fn create(
+        &self,
+        name: &str,
+        file_type: FileType,
+        _mode: InodeMode,
+    ) -> Result<Arc<dyn IndexNode>, SystemError> {
+        if file_type != FileType::Dir {
+            return Err(SystemError::EINVAL);
+        }
+
+        if name.is_empty()
+            || name == "."
+            || name == ".."
+            || name.contains('/')
+            || name.contains('\n')
+        {
+            return Err(SystemError::EINVAL);
+        }
+
+        let this = self.self_ref.upgrade().unwrap();
+        Cgroup2Inode::prune_stale_dir_cache(&this)?;
+
+        let cgroup = {
+            let inner = self.inner.lock();
+            match &inner.kind {
+                Cgroup2InodeKind::Dir { cgroup, children } => {
+                    if children.contains_key(name) || cgroup.child(name).is_some() {
+                        return Err(SystemError::EEXIST);
+                    }
+                    cgroup.clone()
+                }
+                _ => return Err(SystemError::ENOTDIR),
+            }
+        };
+
+        let child_cgroup = cgroup_root().create_child(&cgroup, name)?;
+        let child = Cgroup2Inode::new_dir(name.to_string(), child_cgroup);
+        Cgroup2Inode::add_child(&this, name, child.clone())?;
+        Cgroup2Inode::populate_core_files(&child)?;
+        Ok(child)
+    }
+
+    fn rmdir(&self, name: &str) -> Result<(), SystemError> {
+        if name == "." || name == ".." || name.starts_with("cgroup.") {
+            return Err(SystemError::EINVAL);
+        }
+        let this = self.self_ref.upgrade().unwrap();
+        Cgroup2Inode::prune_stale_dir_cache(&this)?;
+        let child = Cgroup2Inode::lookup_child(&this, name)?;
+
+        {
+            let inner = child.inner.lock();
+            match &inner.kind {
+                Cgroup2InodeKind::Dir {
+                    cgroup,
+                    children: _children,
+                } => {
+                    if cgroup.has_children() {
+                        return Err(SystemError::ENOTEMPTY);
+                    }
+                    if cgroup.has_tasks() {
+                        return Err(SystemError::EBUSY);
+                    }
+                    let parent_cgroup = this.inner.lock();
+                    if let Cgroup2InodeKind::Dir { cgroup: p, .. } = &parent_cgroup.kind {
+                        cgroup_root().remove_child(p, name)?;
+                    }
+                }
+                _ => return Err(SystemError::ENOTDIR),
+            }
+        }
+
+        let mut inner = self.inner.lock();
+        match &mut inner.kind {
+            Cgroup2InodeKind::Dir { children, .. } => {
+                children.remove(name);
+                Ok(())
+            }
+            _ => Err(SystemError::ENOTDIR),
+        }
+    }
+
+    fn unlink(&self, _name: &str) -> Result<(), SystemError> {
+        // cgroup core files are always present and managed by kernel.
+        Err(SystemError::EPERM)
+    }
+
+    fn find(&self, name: &str) -> Result<Arc<dyn IndexNode>, SystemError> {
+        let this = self.self_ref.upgrade().unwrap();
+        let inode = Cgroup2Inode::lookup_child(&this, name)?;
+        Ok(inode)
+    }
+
+    fn fs(&self) -> Arc<dyn FileSystem> {
+        self.fs.read().upgrade().unwrap()
+    }
+
+    fn as_any_ref(&self) -> &dyn Any {
+        self
+    }
+
+    fn list(&self) -> Result<Vec<String>, SystemError> {
+        let this = self.self_ref.upgrade().unwrap();
+        Cgroup2Inode::prune_stale_dir_cache(&this)?;
+        let inner = self.inner.lock();
+        match &inner.kind {
+            Cgroup2InodeKind::Dir { cgroup, children } => {
+                let mut names = vec![".".to_string(), "..".to_string()];
+                for child in cgroup.children_names() {
+                    if !names.iter().any(|n| n == &child) {
+                        names.push(child);
+                    }
+                }
+                names.extend(children.keys().cloned());
+                names.sort();
+                names.dedup();
+                Ok(names)
+            }
+            _ => Err(SystemError::ENOTDIR),
+        }
+    }
+
+    fn dname(&self) -> Result<crate::filesystem::vfs::utils::DName, SystemError> {
+        Ok(self.inner.lock().name.clone().into())
+    }
+}
+
+register_mountable_fs!(Cgroup2Fs, CGROUP2FSMAKER, "cgroup2");
diff --git a/user/apps/c_unitest/test_cgroup_mvp_basic.c b/user/apps/c_unitest/test_cgroup_mvp_basic.c
new file mode 100644
index 00000000..7ba668e1
--- /dev/null
+++ b/user/apps/c_unitest/test_cgroup_mvp_basic.c
@@ -0,0 +1,169 @@
+#define _GNU_SOURCE
+
+#include <errno.h>
+#include <fcntl.h>
+#include <stdio.h>
+#include <stdlib.h>
+#include <string.h>
+#include <sys/mount.h>
+#include <sys/stat.h>
+#include <sys/types.h>
+#include <unistd.h>
+
+/*
+ * 本测试覆盖 cgroup v2 MVP 的基础链路：
+ * 1) /sys/fs/cgroup 存在，且可创建子 cgroup。
+ * 2) 通过写 cgroup.procs 可以迁移当前进程。
+ * 3) /proc/self/cgroup 能反映迁移后的相对路径。
+ * 4) subtree_control 支持空写入，并拒绝未支持的控制器。
+ * 5) 多挂载场景下，创建/删除在不同挂载点之间可见一致。
+ */
+
+static void fail(const char *step) {
+    printf("[FAIL] %s: %s\n", step, strerror(errno));
+    exit(1);
+}
+
+static int path_exists(const char *path) {
+    struct stat st;
+    return stat(path, &st) == 0;
+}
+
+static int ensure_dir(const char *path) {
+    if (mkdir(path, 0755) == 0) {
+        return 0;
+    }
+    if (errno == EEXIST) {
+        return 0;
+    }
+    return -1;
+}
+
+static int write_text(const char *path, const char *text) {
+    int fd = open(path, O_WRONLY);
+    ssize_t n;
+    if (fd < 0) {
+        return -1;
+    }
+    n = write(fd, text, strlen(text));
+    close(fd);
+    return n == (ssize_t)strlen(text) ? 0 : -1;
+}
+
+static int read_text(const char *path, char *buf, size_t len) {
+    int fd = open(path, O_RDONLY);
+    ssize_t n;
+    if (fd < 0) {
+        return -1;
+    }
+    n = read(fd, buf, len - 1);
+    close(fd);
+    if (n < 0) {
+        return -1;
+    }
+    buf[n] = '\0';
+    return 0;
+}
+
+int main(void) {
+    const char *root = "/sys/fs/cgroup";
+    const char *grp = "/sys/fs/cgroup/mvp_basic";
+    const char *procs = "/sys/fs/cgroup/mvp_basic/cgroup.procs";
+    const char *sub = "/sys/fs/cgroup/mvp_basic/cgroup.subtree_control";
+    const char *mnt_a = "/tmp/cgmm_a";
+    const char *mnt_b = "/tmp/cgmm_b";
+    const char *cg_name = "cg_multi_basic";
+    char path_a[256];
+    char path_b[256];
+    char buf[512];
+
+    if (!path_exists(root)) {
+        errno = ENOENT;
+        fail("check /sys/fs/cgroup exists");
+    }
+
+    if (ensure_dir(grp) != 0) {
+        fail("mkdir /sys/fs/cgroup/mvp_basic");
+    }
+
+    if (write_text(procs, "0\n") != 0) {
+        fail("migrate self by writing cgroup.procs");
+    }
+
+    if (read_text("/proc/self/cgroup", buf, sizeof(buf)) != 0) {
+        fail("read /proc/self/cgroup");
+    }
+    if (strstr(buf, "0::/mvp_basic") == NULL) {
+        printf("[FAIL] unexpected /proc/self/cgroup: %s\n", buf);
+        return 1;
+    }
+
+    /* 空写入应当被接受，且 subtree_control 内容保持不变。 */
+    if (write_text(sub, "\n") != 0) {
+        fail("write empty subtree_control");
+    }
+    if (read_text(sub, buf, sizeof(buf)) != 0) {
+        fail("read subtree_control");
+    }
+    if (strcmp(buf, "\n") != 0) {
+        printf("[FAIL] unexpected subtree_control content: %s\n", buf);
+        return 1;
+    }
+
+    /* MVP 阶段未支持的控制器应当返回失败。 */
+    errno = 0;
+    if (write_text(sub, "+cpu\n") == 0) {
+        printf("[FAIL] +cpu unexpectedly succeeded\n");
+        return 1;
+    }
+    if (errno != EINVAL && errno != EPERM) {
+        printf("[FAIL] +cpu unexpected errno: %d\n", errno);
+        return 1;
+    }
+
+    if (ensure_dir(mnt_a) != 0 || ensure_dir(mnt_b) != 0) {
+        fail("prepare multi-mount directories");
+    }
+
+    if (mount("none", mnt_a, "cgroup2", 0, NULL) < 0) {
+        fail("mount cgroup2 on mnt_a");
+    }
+    if (mount("none", mnt_b, "cgroup2", 0, NULL) < 0) {
+        umount(mnt_a);
+        fail("mount cgroup2 on mnt_b");
+    }
+
+    snprintf(path_a, sizeof(path_a), "%s/%s", mnt_a, cg_name);
+    snprintf(path_b, sizeof(path_b), "%s/%s", mnt_b, cg_name);
+
+    if (mkdir(path_a, 0755) < 0) {
+        umount(mnt_b);
+        umount(mnt_a);
+        fail("create cgroup from mount A");
+    }
+    if (access(path_b, F_OK) != 0) {
+        printf("[FAIL] cross-mount visibility missing: %s\n", path_b);
+        umount(mnt_b);
+        umount(mnt_a);
+        return 1;
+    }
+
+    if (rmdir(path_b) < 0) {
+        umount(mnt_b);
+        umount(mnt_a);
+        fail("remove cgroup from mount B");
+    }
+    if (access(path_a, F_OK) == 0 || errno != ENOENT) {
+        printf("[FAIL] cross-mount removal visibility failed: %s\n", path_a);
+        umount(mnt_b);
+        umount(mnt_a);
+        return 1;
+    }
+
+    if (umount(mnt_b) < 0 || umount(mnt_a) < 0) {
+        fail("umount multi-mount points");
+    }
+
+    printf("[PASS] cgroup_mvp_basic\n");
+    return 0;
+}
diff --git a/kernel/src/cgroup/core.rs b/kernel/src/cgroup/core.rs
new file mode 100644
index 00000000..12c8e481
--- /dev/null
+++ b/kernel/src/cgroup/core.rs
@@ -0,0 +1,440 @@
+use alloc::{
+    string::{String, ToString},
+    sync::{Arc, Weak},
+    vec::Vec,
+};
+use core::sync::atomic::{AtomicU64, AtomicUsize, Ordering};
+use hashbrown::{HashMap, HashSet};
+use system_error::SystemError;
+
+use crate::{
+    libs::{rwlock::RwLock, spinlock::SpinLock},
+    process::RawPid,
+};
+
+#[derive(Debug)]
+pub struct CgroupNode {
+    id: usize,
+    name: String,
+    parent: Option<Weak<CgroupNode>>,
+    children: RwLock<HashMap<String, Arc<CgroupNode>>>,
+    tasks: RwLock<HashSet<RawPid>>,
+    //任务集合
+    subtree_control: RwLock<HashSet<String>>,
+    pids_max: RwLock<Option<usize>>,
+    pids_events_max: AtomicU64,
+}
+
+impl CgroupNode {
+    fn new_root() -> Arc<Self> {
+        Arc::new(Self {
+            id: 1,
+            name: String::new(),
+            parent: None,
+            children: RwLock::new(HashMap::new()),
+            tasks: RwLock::new(HashSet::new()),
+            subtree_control: RwLock::new(HashSet::new()),
+            pids_max: RwLock::new(None),
+            pids_events_max: AtomicU64::new(0),
+        })
+    }
+
+    fn new_child(id: usize, name: String, parent: &Arc<CgroupNode>) -> Arc<Self> {
+        Arc::new(Self {
+            id,
+            name,
+            parent: Some(Arc::downgrade(parent)),
+            children: RwLock::new(HashMap::new()),
+            tasks: RwLock::new(HashSet::new()),
+            subtree_control: RwLock::new(HashSet::new()),
+            pids_max: RwLock::new(None),
+            pids_events_max: AtomicU64::new(0),
+        })
+    }
+
+    pub fn id(&self) -> usize {
+        self.id
+    }
+
+    pub fn name(&self) -> &str {
+        &self.name
+    }
+
+    pub fn parent(&self) -> Option<Arc<CgroupNode>> {
+        self.parent.as_ref().and_then(|p| p.upgrade())
+    }
+
+    pub fn add_task(&self, pid: RawPid) {
+        self.tasks.write().insert(pid);
+    }
+
+    pub fn remove_task(&self, pid: RawPid) {
+        self.tasks.write().remove(&pid);
+    }
+
+    pub fn tasks(&self) -> Vec<RawPid> {
+        self.tasks.read().iter().cloned().collect()
+    }
+
+    pub fn children_names(&self) -> Vec<String> {
+        self.children.read().keys().cloned().collect()
+    }
+
+    pub fn children(&self) -> Vec<Arc<CgroupNode>> {
+        self.children.read().values().cloned().collect()
+    }
+
+    pub fn child(&self, name: &str) -> Option<Arc<CgroupNode>> {
+        self.children.read().get(name).cloned()
+    }
+
+    pub fn has_children(&self) -> bool {
+        !self.children.read().is_empty()
+    }
+
+    pub fn has_tasks(&self) -> bool {
+        !self.tasks.read().is_empty()
+    }
+
+    pub fn subtree_control(&self) -> Vec<String> {
+        self.subtree_control.read().iter().cloned().collect()
+    }
+
+    pub fn set_subtree_control(&self, controllers: HashSet<String>) {
+        *self.subtree_control.write() = controllers;
+    }
+
+    pub fn pids_max(&self) -> Option<usize> {
+        *self.pids_max.read()
+    }
+
+    pub fn set_pids_max(&self, max: Option<usize>) {
+        *self.pids_max.write() = max;
+    }
+
+    pub fn pids_events_max(&self) -> u64 {
+        self.pids_events_max.load(Ordering::Relaxed)
+    }
+
+    pub fn inc_pids_events_max(&self) {
+        self.pids_events_max.fetch_add(1, Ordering::Relaxed);
+    }
+
+    pub fn subtree_task_count(self: &Arc<Self>) -> usize {
+        let mut total = self.tasks.read().len();
+        for child in self.children() {
+            total = total.saturating_add(child.subtree_task_count());
+        }
+        total
+    }
+
+    pub fn is_ancestor_of(self: &Arc<Self>, other: &Arc<Self>) -> bool {
+        if Arc::ptr_eq(self, other) {
+            return true;
+        }
+
+        let mut cur = other.parent();
+        while let Some(node) = cur {
+            if Arc::ptr_eq(self, &node) {
+                return true;
+            }
+            cur = node.parent();
+        }
+
+        false
+    }
+}
+
+#[derive(Debug)]
+pub struct CgroupRoot {
+    root: Arc<CgroupNode>,
+    next_id: AtomicUsize,
+    all_nodes: SpinLock<HashMap<usize, Arc<CgroupNode>>>,
+}
+
+impl CgroupRoot {
+    fn new() -> Arc<Self> {
+        let root = CgroupNode::new_root();
+        let mut all_nodes = HashMap::new();
+        all_nodes.insert(root.id(), root.clone());
+
+        Arc::new(Self {
+            root,
+            next_id: AtomicUsize::new(2),
+            all_nodes: SpinLock::new(all_nodes),
+        })
+    }
+
+    pub fn root(&self) -> Arc<CgroupNode> {
+        self.root.clone()
+    }
+
+    #[allow(dead_code)]
+    pub fn lookup_by_id(&self, id: usize) -> Option<Arc<CgroupNode>> {
+        self.all_nodes.lock().get(&id).cloned()
+    }
+
+    pub fn create_child(
+        &self,
+        parent: &Arc<CgroupNode>,
+        name: &str,
+    ) -> Result<Arc<CgroupNode>, SystemError> {
+        if name.is_empty() || name == "." || name == ".." || name.contains('/') {
+            return Err(SystemError::EINVAL);
+        }
+        //先找寻有无节点，避免重复创建
+        {
+            let children = parent.children.read();
+            if let Some(existing) = children.get(name) {
+                return Ok(existing.clone());
+            }
+        }
+
+        let id = self.next_id.fetch_add(1, Ordering::Relaxed);
+        let child = CgroupNode::new_child(id, name.to_string(), parent);
+
+        {
+            let mut children = parent.children.write();
+            if let Some(existing) = children.get(name) {
+                return Ok(existing.clone());
+            }
+            children.insert(name.to_string(), child.clone());
+        }
+
+        self.all_nodes.lock().insert(id, child.clone());
+        Ok(child)
+    }
+
+    pub fn remove_child(&self, parent: &Arc<CgroupNode>, name: &str) -> Result<(), SystemError> {
+        let child = {
+            let children = parent.children.read();
+            children.get(name).cloned().ok_or(SystemError::ENOENT)?
+        };
+        //有孩子时返回busy错误
+        if child.has_children() || child.has_tasks() {
+            return Err(SystemError::EBUSY);
+        }
+
+        parent.children.write().remove(name);
+        self.all_nodes.lock().remove(&child.id());
+        Ok(())
+    }
+
+    #[allow(dead_code)]
+    pub fn find_or_create_path(&self, path: &str) -> Result<Arc<CgroupNode>, SystemError> {
+        let rel = normalize_cgroup_abs_path(path)?;
+        let mut cur = self.root();
+
+        if rel.is_empty() {
+            return Ok(cur);
+        }
+
+        for comp in rel.split('/') {
+            if comp.is_empty() {
+                continue;
+            }
+            cur = self.create_child(&cur, comp)?;
+        }
+
+        Ok(cur)
+    }
+
+    pub fn find_path(&self, path: &str) -> Result<Arc<CgroupNode>, SystemError> {
+        let rel = normalize_cgroup_abs_path(path)?;
+        let mut cur = self.root();
+
+        if rel.is_empty() {
+            return Ok(cur);
+        }
+
+        for comp in rel.split('/') {
+            if comp.is_empty() {
+                continue;
+            }
+            let next = cur
+                .children
+                .read()
+                .get(comp)
+                .cloned()
+                .ok_or(SystemError::ENOENT)?;
+            cur = next;
+        }
+
+        Ok(cur)
+    }
+}
+
+#[derive(Debug, Clone)]
+pub struct TaskCgroupRef {
+    node: Arc<CgroupNode>,
+}
+
+impl TaskCgroupRef {
+    pub fn new(node: Arc<CgroupNode>) -> Self {
+        Self { node }
+    }
+
+    pub fn node(&self) -> Arc<CgroupNode> {
+        self.node.clone()
+    }
+}
+
+lazy_static! {
+    static ref CGROUP_ROOT: Arc<CgroupRoot> = CgroupRoot::new();
+    static ref CGROUP_ACCOUNTING_LOCK: SpinLock<()> = SpinLock::new(());
+}
+
+pub fn cgroup_root() -> &'static Arc<CgroupRoot> {
+    &CGROUP_ROOT
+}
+
+pub fn cgroup_root_node() -> Arc<CgroupNode> {
+    CGROUP_ROOT.root()
+}
+
+pub fn cgroup_accounting_lock() -> &'static SpinLock<()> {
+    &CGROUP_ACCOUNTING_LOCK
+}
+
+pub fn cgroup_path_relative_to_node(node: &Arc<CgroupNode>, view_root: &Arc<CgroupNode>) -> String {
+    if !view_root.is_ancestor_of(node) {
+        return "/".to_string();
+    }
+
+    let node_path = cgroup_path_components(node);
+    let root_path = cgroup_path_components(view_root);
+
+    let down = &node_path[root_path.len()..];
+
+    if down.is_empty() {
+        return "/".to_string();
+    }
+
+    format!("/{}", down.join("/"))
+}
+
+pub fn cgroup_path_from_view(node: &Arc<CgroupNode>, view_root: &Arc<CgroupNode>) -> String {
+    cgroup_path_relative_to_node(node, view_root)
+}
+
+pub fn cgroup_common_ancestor(left: &Arc<CgroupNode>, right: &Arc<CgroupNode>) -> Arc<CgroupNode> {
+    let mut cur = Some(left.clone());
+    while let Some(node) = cur {
+        if node.is_ancestor_of(right) {
+            return node;
+        }
+        cur = node.parent();
+    }
+    cgroup_root_node()
+}
+//一个已经作为管理节点的node不能同时作为迁移目的地承载普通节点
+pub fn cgroup_migrate_vet_dst(dst: &Arc<CgroupNode>) -> Result<(), SystemError> {
+    // v2 no-internal-process 最小约束：
+    // 目标 cgroup 如果已经有进程并且启用了 subtree_control，则拒绝迁移。
+    if dst.has_tasks() && !dst.subtree_control().is_empty() {
+        return Err(SystemError::EBUSY);
+    }
+    Ok(())
+}
+//fork前pids.max检查
+pub fn cgroup_can_fork_in(node: &Arc<CgroupNode>, new_tasks: usize) -> Result<(), SystemError> {
+    let mut cur = Some(node.clone());
+    while let Some(cg) = cur {
+        if let Some(max) = cg.pids_max() {
+            let used = cg.subtree_task_count();
+            if used.saturating_add(new_tasks) > max {
+                cg.inc_pids_events_max();
+                return Err(SystemError::EAGAIN_OR_EWOULDBLOCK);
+            }
+        }
+        cur = cg.parent();
+    }
+    Ok(())
+}
+
+pub fn cgroup_migrate_vet_dst_with_src(
+    src: &Arc<CgroupNode>,
+    dst: &Arc<CgroupNode>,
+    moved_tasks: usize,
+) -> Result<(), SystemError> {
+    cgroup_migrate_vet_dst(dst)?;
+
+    let mut cur = Some(dst.clone());
+    while let Some(cg) = cur {
+        if let Some(max) = cg.pids_max() {
+            let used = cg.subtree_task_count();
+            let delta = if cg.is_ancestor_of(src) {
+                0
+            } else {
+                moved_tasks
+            };
+            if used.saturating_add(delta) > max {
+                cg.inc_pids_events_max();
+                return Err(SystemError::EAGAIN_OR_EWOULDBLOCK);
+            }
+        }
+        cur = cg.parent();
+    }
+
+    Ok(())
+}
+
+#[allow(dead_code)]
+pub fn find_or_create_node_by_abs_path(path: &str) -> Result<Arc<CgroupNode>, SystemError> {
+    cgroup_root().find_or_create_path(path)
+}
+
+pub fn find_node_by_abs_path(path: &str) -> Result<Arc<CgroupNode>, SystemError> {
+    cgroup_root().find_path(path)
+}
+
+fn cgroup_path_components(node: &Arc<CgroupNode>) -> Vec<String> {
+    let mut rev = Vec::new();
+    let mut cur = Some(node.clone());
+
+    while let Some(n) = cur {
+        if !n.name().is_empty() {
+            rev.push(n.name().to_string());
+        }
+        cur = n.parent();
+    }
+
+    rev.reverse();
+    rev
+}
+
+fn normalize_cgroup_abs_path(path: &str) -> Result<String, SystemError> {
+    // 支持两种形式：
+    // 1) cgroup v2 路径："/foo/bar"
+    // 2) 绝对挂载路径："/sys/fs/cgroup/foo/bar"
+    let rel = if let Some(stripped) = path.strip_prefix("/sys/fs/cgroup") {
+        stripped
+    } else {
+        path
+    };
+
+    if rel.is_empty() {
+        return Ok(String::new());
+    }
+
+    if !rel.starts_with('/') {
+        return Err(SystemError::EINVAL);
+    }
+
+    let mut out = Vec::new();
+    //单调栈处理..和.
+    for comp in rel.split('/') {
+        if comp.is_empty() || comp == "." {
+            continue;
+        }
+        if comp == ".." {
+            if out.pop().is_none() {
+                return Err(SystemError::EINVAL);
+            }
+            continue;
+        }
+        out.push(comp);
+    }
+
+    Ok(out.join("/"))
+}
